import { describe, expect, it } from 'vitest';
import type { ProjectEvent } from '@agent-foundry/contracts';
import { redactEvent, redactString } from './redaction.js';

function baseEvent(overrides: Partial<ProjectEvent> = {}): ProjectEvent {
  return {
    id: 'event-1',
    projectId: 'project-1',
    type: 'agent.completed',
    createdAt: '2026-07-14T12:00:00.000Z',
    nodeId: 'implement',
    runId: 'run-1',
    message: 'Step implement completed successfully in 4200ms.',
    dedupeKey: 'dedupe-key-1',
    data: {},
    ...overrides,
  };
}

describe('redactString', () => {
  it('redacts a bearer token embedded in text', () => {
    const secret = 'abcd1234efgh5678ijkl9012mnop3456';
    const result = redactString(`Authorization: Bearer ${secret}`);
    expect(result).not.toContain(secret);
    expect(result).toContain('[REDACTED]');
  });

  it('redacts an sk- style secret key embedded in text', () => {
    const secret = 'sk-proj-A1b2C3d4E5f6G7h8I9j0K1l2M3n4O5p6Q7r8S9t0';
    const result = redactString(`OPENAI_API_KEY=${secret}`);
    expect(result).not.toContain(secret);
    expect(result).toContain('[REDACTED]');
  });

  it('redacts a ghp_ style GitHub token embedded in text', () => {
    const secret = 'ghp_1234567890ABCDEFghijklmnopqrstuvwxyz12';
    const result = redactString(
      `git remote set-url origin https://${secret}@github.com/org/repo.git`,
    );
    expect(result).not.toContain(secret);
    expect(result).toContain('[REDACTED]');
  });

  it('redacts a JWT embedded in text', () => {
    const secret =
      'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJzdWIiOiIxMjM0NTY3ODkwIn0.SflKxwRJSMeKKF2QT4fwpMeJf36POk6yJV_adQssw5c';
    const result = redactString(`Set-Cookie: session=${secret}; Path=/`);
    expect(result).not.toContain(secret);
    expect(result).toContain('[REDACTED]');
  });

  it('leaves ordinary text untouched', () => {
    const message = 'Step implement completed successfully in 4200ms.';
    expect(redactString(message)).toBe(message);
  });
});

describe('redactEvent', () => {
  it('redacts secrets embedded in the message', () => {
    const secret = 'ghp_1234567890ABCDEFghijklmnopqrstuvwxyz12';
    const event = baseEvent({ message: `Pushed using token ${secret}` });

    const redacted = redactEvent(event);

    expect(redacted.message).not.toContain(secret);
    expect(redacted.message).toContain('[REDACTED]');
  });

  it('redacts sensitive keys recursively in data, including nested objects and arrays', () => {
    const event = baseEvent({
      data: {
        author: 'agent-foundry-bot',
        apiKey: 'super-secret-api-key-value',
        accessToken: 'super-secret-access-token-value',
        nested: {
          clientSecret: 'super-secret-client-secret-value',
          password: 'super-secret-password-value',
          nodeId: 'node-xyz',
          dedupeKey: 'dedupe-xyz',
        },
        items: [
          { apiKey: 'array-secret-api-key', author: 'array-author' },
          { password: 'array-secret-password', nodeId: 'array-node-id' },
        ],
      },
    });

    const redacted = redactEvent(event);
    const data = redacted.data as Record<string, unknown>;
    const nested = data.nested as Record<string, unknown>;
    const items = data.items as Array<Record<string, unknown>>;

    // sensitive keys, including camelCase compounds, are redacted at every depth
    expect(data.apiKey).toBe('[REDACTED]');
    expect(data.accessToken).toBe('[REDACTED]');
    expect(nested.clientSecret).toBe('[REDACTED]');
    expect(nested.password).toBe('[REDACTED]');
    expect(items[0]?.apiKey).toBe('[REDACTED]');
    expect(items[1]?.password).toBe('[REDACTED]');

    // non-sensitive keys are left untouched
    expect(data.author).toBe('agent-foundry-bot');
    expect(nested.nodeId).toBe('node-xyz');
    expect(nested.dedupeKey).toBe('dedupe-xyz');
    expect(items[0]?.author).toBe('array-author');
    expect(items[1]?.nodeId).toBe('array-node-id');
  });
});
